  ('locality-7c9828ae-moex-00296', 'locality-7c9828ae', 'locality-7c9828ae-moex-110-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '行政訴訟法上有關交通裁決事件之規定，下列敘述何者錯誤？', '["應經訴願前置程序，向原處分之上級機關提起訴願", "被告機關收受起訴狀繕本後，應於20日內重新審查原處分是否妥當", "由原告住所地、居住所、所在地或違規行為地之地方法院行政訴訟庭管轄", "交通裁決事件之審理，原則上準用簡易訴訟程序之規定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:08+00:00", "source_pdf_sha1": "4cc3d93276fc", "answer_pdf_sha1": "85c740cb7eda", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "405", "s": "0609", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
