  ('locality-7c9828ae-moex-00298', 'locality-7c9828ae', 'locality-7c9828ae-moex-110-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '依最高行政法院實務見解，關於公立大學對其所屬教師作成不續聘決定之敘述，下列何者正確？', '["再申訴決定不予維持大學不續聘決定時，大學得就該再申訴決定提起行政訴訟", "當事人不服不續聘決定，須經申訴、再申訴以及訴願，方得提起撤銷訴訟", "當事人不服不續聘決定提起撤銷訴訟時，應以核准不續聘處分之主管教育行政機關為被告", "不續聘決定於主管教育行政機關核准前，當事人即得依法對之進行權利救濟程序"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:08+00:00", "source_pdf_sha1": "4cc3d93276fc", "answer_pdf_sha1": "85c740cb7eda", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "405", "s": "0609", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
  ('locality-7c9828ae-moex-00299', 'locality-7c9828ae', 'locality-7c9828ae-moex-110-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '關於收容聲請事件程序，下列敘述何者錯誤？', '["以地方法院行政訴訟庭為第一審管轄法院", "包括依行政執行法所為之拘提、管收等限制人身自由之措施", "不適用行政訴訟法通常「以原告就被告」之定管轄原則", "針對法院收容聲請事件之裁定不服者，得向高等行政法院提出抗告"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:08+00:00", "source_pdf_sha1": "4cc3d93276fc", "answer_pdf_sha1": "85c740cb7eda", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "405", "s": "0609", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
  ('locality-7c9828ae-moex-00300', 'locality-7c9828ae', 'locality-7c9828ae-moex-110-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '人民因自己土地遭行政機關徵收，而請求發給款項，該請求權之性質為何？', '["公法上結果除去請求權", "國家賠償請求權", "損失補償請求權", "公法上不當得利請求權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:08+00:00", "source_pdf_sha1": "4cc3d93276fc", "answer_pdf_sha1": "85c740cb7eda", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "405", "s": "0609", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
  ('locality-7c9828ae-moex-00301', 'locality-7c9828ae', 'locality-7c9828ae-moex-110-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '依司法實務見解，關於國家賠償之敘述，下列何者正確？', '["凡供公共或公務使用之設施，以國家或地方自治團體所有者為限，方有國家賠償法之適用", "國家賠償法所定之請求權時效，應以請求權人實際知悉賠償義務機關時開始起算", "因公共設施之設置或管理欠缺所生之國家賠償責任，須以管理或設置機關有過失為必要", "於行政訴訟中合併請求國家賠償者，如行政訴訟因起訴不合程式不合法，行政法院得一併駁回國家賠償 之訴"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:08+00:00", "source_pdf_sha1": "4cc3d93276fc", "answer_pdf_sha1": "85c740cb7eda", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "405", "s": "0609", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
  ('locality-7c9828ae-moex-00302', 'locality-7c9828ae', 'locality-7c9828ae-moex-110-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '行政執行分署通知義務人，將拍賣其房屋。義務人聲明異議未獲救濟後，得採行下列何種方式救濟？', '["提起行政訴訟", "提起訴願", "提起再異議", "提起損失補償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:08+00:00", "source_pdf_sha1": "4cc3d93276fc", "answer_pdf_sha1": "85c740cb7eda", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "405", "s": "0609", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
  ('locality-7c9828ae-moex-00303', 'locality-7c9828ae', 'locality-7c9828ae-moex-110-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '依行政執行法規定，有關即時強制之敘述，下列何者錯誤？', '["行政機關為阻止犯罪，而有即時處置之必要時，得採取即時強制措施", "對於人之管束及對於危險物之扣留，均屬即時強制之方法", "對於人之管束須經法院裁定後始得實施，且最長不得逾24小時", "人民因執行機關依法實施即時強制，致財產受有特別損失時，得請求補償"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:08+00:00", "source_pdf_sha1": "4cc3d93276fc", "answer_pdf_sha1": "85c740cb7eda", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "405", "s": "0609", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
  ('locality-7ec62a85-moex-00001', 'locality-7ec62a85', 'locality-7ec62a85-moex-114-de0a21a2', 'sub-locality-7ec62a85-01', NULL, 'essay', '甲為 A的繼承人平日照護 A的生活起居，某日 A在醫院進行例行體檢，
因為 A有嚴重重聽，醫生告知甲，A的心臟狀況不適合受到過度刺激，
且明說相關有刺激感的遊樂設施都應該避免。回家後，甲沒有將醫生囑
咐向 A 說明，為了早日繼承 A 的財產，甲竟然慫恿 A 乘坐遊樂園中有
高度刺激感之遊樂設施，A果然在搭乘後感覺不適而昏迷，遊樂場工作
人員緊急以救護車送往醫院，幸而將 A救回。豈知 A在被救回後，雖知
自己的心臟可能不能負荷，仍然自覺如能在遊樂園中搭乘遊樂設施而迅
速死亡也是一種死亡方式的選擇，A甚至沉溺於遊樂設施的刺激感，不
但要求甲代為購買遊樂設施玩到飽年票，每週還要甲親自接送其至少一
次的搭乘。不料有一天遊樂設施的安全設備發生重大故障，A跌落在地，
經送醫不治死亡。試問甲的行為依刑法如何處斷？（30 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:08+00:00", "source_pdf_sha1": "df34058c11cf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "316", "s": "0710", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法律廉政"}'::jsonb, NULL)
